import{_ as l,c as e,o as i,al as r}from"./chunks/framework.5cuxq5ua.js";const b=JSON.parse('{"title":"2026-03","description":"","frontmatter":{"outline":[1,8]},"headers":[],"relativePath":"blog/life/日记/2026年日记.md","filePath":"blog/life/日记/2026年日记.md","lastUpdated":1773588608000}'),h={name:"blog/life/日记/2026年日记.md"};function n(d,a,t,o,s,c){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="_2026-03" tabindex="-1">2026-03 <a class="header-anchor" href="#_2026-03" aria-label="Permalink to “2026-03”">​</a></h1><h2 id="_2026-03-15-17-15-星期天" tabindex="-1">2026-03-15 17:15 星期天 <a class="header-anchor" href="#_2026-03-15-17-15-星期天" aria-label="Permalink to “2026-03-15 17:15 星期天”">​</a></h2><h3 id="大夫山骑车🚴🏻‍♀️" tabindex="-1">大夫山骑车🚴🏻‍♀️ <a class="header-anchor" href="#大夫山骑车🚴🏻‍♀️" aria-label="Permalink to “大夫山骑车🚴🏻‍♀️”">​</a></h3><ul><li>昨天第二次去大夫山骑车，第一次还是22年的时候，不过这次去大夫山的水变黄了，之前绿绿的，水清清的，这次去看不怎么好看。不过很多路倒是修好了，比之前好骑，一些小路上的减速带也去掉了，挺不错的。之前吃自嗨锅背后的水塘里面开满了睡莲，不记得之前有了。</li><li>还是这几个月广州的天气好，早晚有温差，也没那么湿热，要是一直都是这样就好了。</li><li>这个季节的广州才有点像冬天，榕树的叶子都掉光了，地上都是落叶，枝头又在冒新芽。走在广州不同的地方闻到的味道也不一样，有时候是芒果花的味道，有时候是紫荆花的味道，有时候是桂花的味道，还有公司柚子树开花的味道，每次在空气里面闻到阵阵花香，对广州的喜欢还是会多一点点，抵消了对他夏天炎热的讨厌。</li></ul><h2 id="_2026-03-07-星期六" tabindex="-1">2026-03-07 星期六 <a class="header-anchor" href="#_2026-03-07-星期六" aria-label="Permalink to “2026-03-07 星期六”">​</a></h2><h3 id="二沙岛广东美术馆德化白瓷展" tabindex="-1">二沙岛广东美术馆德化白瓷展 <a class="header-anchor" href="#二沙岛广东美术馆德化白瓷展" aria-label="Permalink to “二沙岛广东美术馆德化白瓷展”">​</a></h3><ul><li>沿着沿江西路骑到二沙岛的广东美术馆看德化白瓷展，里面最精美的是神话里面的玉漱公主，衣服薄如蝉翼，感觉都不像是瓷能做出来的。非常好看。</li><li>好久没沿着珠江骑车，骑骑车也是相当舒服的。</li></ul><h2 id="_2026-03-03-22-11-星期二" tabindex="-1">2026-03-03 22:11 星期二 <a class="header-anchor" href="#_2026-03-03-22-11-星期二" aria-label="Permalink to “2026-03-03 22:11 星期二”">​</a></h2><h3 id="元宵提前一个小时下班" tabindex="-1">元宵提前一个小时下班 <a class="header-anchor" href="#元宵提前一个小时下班" aria-label="Permalink to “元宵提前一个小时下班”">​</a></h3><ul><li>今天是元宵，广东这边对元宵好像更看重一点，今天还提前了一个小时下班，之前哪有这样的待遇，记录一下。</li><li>提前一个小时下班，感觉自己多了很多时间一样，经过菜市场的时候买了点牛肉，鸡蛋，绿菜，回来把年前买的方便面加了点牛肉煮了，就当过年了。囤的东西又少了一样，但是又多了几个鸡蛋……</li><li>来小饭堂吃饭的同事一下子多了起来，中午吃饭也要排好久的队，希望他们能多加点打饭的阿姨。大家疯抢进入食堂的时候，好像要去抢赈灾粮一样，稍微晚点就没了，好可怕……那场面已经好久没见到了。</li></ul><h2 id="_2026-03-01" tabindex="-1">2026-03-01 <a class="header-anchor" href="#_2026-03-01" aria-label="Permalink to “2026-03-01”">​</a></h2><h3 id="年后大扫除-星期天" tabindex="-1">年后大扫除 星期天 <a class="header-anchor" href="#年后大扫除-星期天" aria-label="Permalink to “年后大扫除 星期天”">​</a></h3><ul><li>过完年后放的第一个周末，只放一天假，就在家里面搞大扫除，人的东西怎么可以那么多，收拾了好多东西出来，过期的药品，过期的食品，一堆杂物箱子，厚厚的灰尘，感觉自己住在垃圾堆里面一样。也收出来很多之前囤积的日用品，真没想到自己在一个物质丰富的年代里面还会囤那么多，很占位置，又后悔自己怎么买了那么多东西，虽然都是后面会用掉的。卖掉了积攒了一年的空瓶子，还有小半山的旧衣服，下周末再处理。</li><li>每次做大扫除的时候，都觉得自己怎么那么能买？但是在平时的生活中，还是会觉得自己东西不够。维持我们正常生活所需要的物品最小单位是什么？刷到网上那些博主改造自己的出租屋，改造后确实很漂亮，很精致，但生活又不是改造完，视频里面分享的那一刻，后面持续生产生活又需要付出多少时间去维持之前的模样？光是想到这些都觉得辛苦，又觉得这些博主有点过度改造了。我一直都有刻意在控制自己所需物品的数量，不囤物资，可是不知不觉中东西还是很多。慢慢堆积起来的垃圾袋已经又有一大口袋了，零食也有好多。</li><li>打扫的干干净净，东西扔掉很多东西，屋子都宽敞了好多，舒服~~~~~~</li></ul><h1 id="_2026-01" tabindex="-1">2026-01 <a class="header-anchor" href="#_2026-01" aria-label="Permalink to “2026-01”">​</a></h1><h2 id="_2026-01-31-21-44-星期六" tabindex="-1">2026-01-31 21:44 星期六 <a class="header-anchor" href="#_2026-01-31-21-44-星期六" aria-label="Permalink to “2026-01-31 21:44 星期六”">​</a></h2><h3 id="骑车水声水库🚴🏻‍♀️" tabindex="-1">骑车水声水库🚴🏻‍♀️ <a class="header-anchor" href="#骑车水声水库🚴🏻‍♀️" aria-label="Permalink to “骑车水声水库🚴🏻‍♀️”">​</a></h3><ul><li>这段路还是很有难度的，是我在strava上第二的爬升高度。有几个坡差点要上不去。沿着水库的路也是起起伏伏，不是平路，还好是逆时针环水库，顺时针的话，我可能上不来那座山，菜腿，哈哈哈。</li></ul><h2 id="_2026-01-30-22-05-星期五" tabindex="-1">2026-01-30 22:05 星期五 <a class="header-anchor" href="#_2026-01-30-22-05-星期五" aria-label="Permalink to “2026-01-30 22:05 星期五”">​</a></h2><h3 id="跟金爱一起逛山姆-🏪" tabindex="-1">跟金爱一起逛山姆 🏪 <a class="header-anchor" href="#跟金爱一起逛山姆-🏪" aria-label="Permalink to “跟金爱一起逛山姆 🏪”">​</a></h3><ul><li>跟金爱一起逛了山姆，逛完在外面一起吃了牛肉卷跟披萨，牛肉很多，下次去逛的时候，提前带一个分装盒，想买什么可以分着一起买。</li></ul><h2 id="_2026-01-25-21-49-星期六" tabindex="-1">2026-01-25 21:49 星期六 <a class="header-anchor" href="#_2026-01-25-21-49-星期六" aria-label="Permalink to “2026-01-25 21:49 星期六”">​</a></h2><h3 id="香港麦理浩径徒步-🏃🏻‍♀️" tabindex="-1">香港麦理浩径徒步 🏃🏻‍♀️ <a class="header-anchor" href="#香港麦理浩径徒步-🏃🏻‍♀️" aria-label="Permalink to “香港麦理浩径徒步 🏃🏻‍♀️”">​</a></h3><ul><li>爬了好几座山，累是真的累，风景好是真的好，海水太蓝了，远远的望着那一片白色的沙滩蓝色的海水真实美极了，本来那天温度不是很高，但是在徒步几乎没有树荫，非常的晒，一路上都是尘土。</li><li>路上厕所比较少，但又很热，又不敢多喝水。</li><li>很开心，又挑战了一段很难走的路。看到了那么美丽的风景，跟好朋友们一起徒步，看到那么美丽的风景，真是人生一大美事。</li></ul><h2 id="_2026-01-18-22-09-星期天" tabindex="-1">2026-01-18 22:09 星期天 <a class="header-anchor" href="#_2026-01-18-22-09-星期天" aria-label="Permalink to “2026-01-18 22:09 星期天”">​</a></h2><h3 id="《翠湖》、徒步黄埔区好几个公园" tabindex="-1">《翠湖》、徒步黄埔区好几个公园 <a class="header-anchor" href="#《翠湖》、徒步黄埔区好几个公园" aria-label="Permalink to “《翠湖》、徒步黄埔区好几个公园”">​</a></h3><ul><li>周六在星寰看了电影《翠湖》，很不错，《昆明》这首歌也好好听。<a href="/read/观影阅读记录.html#_2026">翠湖</a></li><li>徒步路线也是在小红书上搜到的，路线不长，串起了好几个黄埔区科学城这边的公园，路程不长8Km左右，爬升也不大，散散步，很舒服。</li></ul><h2 id="_2026-01-12-21-43-星期一" tabindex="-1">2026-01-12 21:43 星期一 <a class="header-anchor" href="#_2026-01-12-21-43-星期一" aria-label="Permalink to “2026-01-12 21:43 星期一”">​</a></h2><h3 id="新办公室一周-爱酱博客-动人的旋律" tabindex="-1">新办公室一周 爱酱博客 动人的旋律 <a class="header-anchor" href="#新办公室一周-爱酱博客-动人的旋律" aria-label="Permalink to “新办公室一周 爱酱博客 动人的旋律”">​</a></h3><ul><li>新年的第一个星期，就在努力适应新环境中度过，新的办公室，适应网络，适应新的工作节奏。新办公室旁边在施工，咚咚咚的声音，每天都很吵，还在打地基，如果打好了应该就没那么难受了。不能用互联网确实比较麻烦，现在都在积极融入AI，用不了网感觉都在倒退一样。坐到领导旁边，现在感觉也还好，领导人很好，时不时的递过来一个水果，零食啥的，他的话感觉也很多，领导心态真不错，哈哈哈。这边的工位很宽，脚放直之后，也不会踢到对面的同事。还挺好的。就是感觉装修的味道还是没有完全散去，也不知道对身体到底会造成多大的影响。</li><li>今天还看了爱酱的博客，很不错，她的动手能力太强了，一步步的用着AI搭建起来，真厉害。看了她的博客内容，感觉她是一个很积极的人，写的文字都能感觉到向上，很有活力，真不错，可以看看这种有活力的文字。</li><li>上周六的时候发现一首非常好听的歌，是韩语歌，翻译成中文是《致犹豫的恋人们》，听不懂在唱什么，但是旋律就很打动我，一下子让我想到了电影《初吻》的经典画面，戴上耳机播放着《Reality》世界都安静了。中午在办公室两只耳朵都带着耳机，一直循环这首歌，安安静静的迁移博客也好，看书也好，好舒服。</li></ul>',29)])])}const f=l(h,[["render",n]]);export{b as __pageData,f as default};
